-- ----------------------------------------------------------------------------
-- FRENTE 2b — normaliza status de TODO NPC flagado
--   (os 666 novos + ~220 antigos ja flagados) -> status 'humanoid_npc'
-- ----------------------------------------------------------------------------
UPDATE ref_criaturas SET status_conversao = 'humanoid_npc'
WHERE humanoid_npc = true
  AND status_conversao = 'pendente';

-- ----------------------------------------------------------------------------
-- POST-CHECK (eyeball antes do COMMIT)
-- ----------------------------------------------------------------------------
-- (a) status 'classificada' deve ter subido em 494 (Frente 1)
SELECT COUNT(*) AS post_classificada
FROM ref_criaturas WHERE status_conversao = 'classificada';

-- (b) origem preenchida deve ter subido em 494 (Frente 1)
SELECT COUNT(*) AS post_origem_preenchida
FROM ref_criaturas WHERE origem IS NOT NULL;

-- (c) humanoid_npc = true deve dar 886 (666 novos + 220 antigos)
SELECT COUNT(*) AS post_humanoid_npc_true
FROM ref_criaturas WHERE humanoid_npc = true;

-- (d) status 'humanoid_npc' deve dar 886
SELECT COUNT(*) AS post_status_humanoid_npc
FROM ref_criaturas WHERE status_conversao = 'humanoid_npc';

